Literal.Value:
'{
  "$schema": "https://vega.github.io/schema/vega/v5.json",
  "width": 954,
  "height": 728,
  "padding": 0,
  "autosize": {
    "type": "none",
    "contains": "padding"
  },
  "data": [
    {
      "name": "dataset"
    }
  ],
  "scales": [
    {
      "name": "color",
      "type": "pow",
      "exponent": 0.45,
      "domain": {
        "data": "dataset",
        "field": "Sales"
      },
      "range": [
        "#DCEAF6",
        "#073B72"
      ],
      "zero": false,
      "nice": false
    }
  ],
  "marks": [
    {
      "type": "rect",
      "encode": {
        "enter": {
          "x": {
            "value": 0
          },
          "y": {
            "value": 0
          },
          "width": {
            "signal": "width"
          },
          "height": {
            "signal": "height"
          },
          "fill": {
            "value": "#FFFFFF"
          }
        }
      }
    },
    {
      "type": "path",
      "from": {
        "data": "dataset"
      },
      "encode": {
        "enter": {
          "path": {
            "field": "SvgPath"
          },
          "stroke": {
            "value": "#AFC2D5"
          },
          "strokeWidth": {
            "value": 1.2
          },
          "cursor": {
            "value": "pointer"
          },
          "tooltip": {
            "signal": "{\"Governorate\": datum.Governorate, \"Sales\": format(datum.Sales, \",.0f\") + \" \u062f.\u0639\", \"Customers\": format(isValid(datum.Customers) ? datum.Customers : (isValid(datum[''Governorate Tooltip Customer Count'']) ? datum[''Governorate Tooltip Customer Count''] : (isValid(datum[''_Measures.Governorate Tooltip Customer Count'']) ? datum[''_Measures.Governorate Tooltip Customer Count''] : 0)), \",.0f\"), \"Sales %\": format(isValid(datum.SalesPct) ? datum.SalesPct : (isValid(datum[''Governorate Sales % of Total'']) ? datum[''Governorate Sales % of Total''] : (isValid(datum[''_Measures.Governorate Sales % of Total'']) ? datum[''_Measures.Governorate Sales % of Total''] : 0)), \".2%\")}"
          },
          "x": {
            "signal": "offsetX"
          },
          "y": {
            "signal": "offsetY"
          },
          "scaleX": {
            "signal": "mapScale"
          },
          "scaleY": {
            "signal": "mapScale"
          }
        },
        "update": {
          "fill": [
            {
              "test": "datum.Sales > 0",
              "scale": "color",
              "field": "Sales"
            },
            {
              "value": "#F2F6FA"
            }
          ],
          "fillOpacity": {
            "value": 1
          },
          "stroke": {
            "value": "#AFC2D5"
          },
          "strokeWidth": {
            "value": 0.9
          }
        },
        "hover": {
          "fillOpacity": {
            "value": 0.94
          },
          "stroke": {
            "value": "#AFC2D5"
          },
          "strokeWidth": {
            "value": 0.9
          }
        }
      }
    }
  ],
  "signals": [
    {
      "name": "designMinX",
      "value": 28
    },
    {
      "name": "designMinY",
      "value": 34.5
    },
    {
      "name": "designContentWidth",
      "value": 684
    },
    {
      "name": "designContentHeight",
      "value": 581
    },
    {
      "name": "mapScale",
      "update": "min(width / designContentWidth, height / designContentHeight) * 0.99"
    },
    {
      "name": "offsetX",
      "update": "(width - designContentWidth * mapScale) / 2 - designMinX * mapScale"
    },
    {
      "name": "offsetY",
      "update": "(height - designContentHeight * mapScale) / 2 - designMinY * mapScale"
    }
  ]
}'
